-- Case 007: COPY INTO table with nested SELECT transformations and metadata columns
COPY INTO RAW.ORDER_JSON_LANDING(event_id,event_time,tenant_id,order_id,payload,source_filename,source_row_number,file_content_key,loaded_at) FROM(SELECT $1:event_id::STRING AS event_id,TRY_TO_TIMESTAMP_TZ($1:event_time::STRING) AS event_time,COALESCE($1:tenant::STRING, 'UNKNOWN') AS tenant_id,$1:order:id::STRING AS order_id,OBJECT_INSERT($1, '_load_context',OBJECT_CONSTRUCT( 'file',METADATA$FILENAME, 'row',METADATA$FILE_ROW_NUMBER, 'start_scan_time',METADATA$START_SCAN_TIME),TRUE) AS payload,METADATA$FILENAME AS source_filename,METADATA$FILE_ROW_NUMBER AS source_row_number,METADATA$FILE_CONTENT_KEY AS file_content_key,METADATA$START_SCAN_TIME AS loaded_at FROM @RAW.EXT_EVENT_STAGE/orders/2026/06/(FILE_FORMAT => RAW.FF_JSON_LINES)) PATTERN = '.*orders_(jp|kr|sa|global)_[0-9]{8}_[0-9]{6}\\.jsonl(\\.gz)?' ON_ERROR = 'SKIP_FILE_5%' PURGE = FALSE FORCE = FALSE RETURN_FAILED_ONLY = FALSE SIZE_LIMIT = 5368709120;
